import { createClient } from '@/lib/supabase/server';
import AddVideoForm from '@/components/admin/AddVideoForm';
import DeleteVideoButton from '@/components/admin/DeleteVideoButton';
import { Video as VideoType } from '@/types';
import { Pencil, Filter, PlayCircle, Video, ExternalLink, Tag, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { SearchInput } from '@/components/ui/SearchInput';
import { getAdminPermissions } from '@/lib/supabase/permissions';

export const metadata = {
  title: 'Video Archive | Admin Portal',
};

interface PageProps {
  searchParams: Promise<{ q?: string }>;
}

export default async function AdminVideosPage({ searchParams }: PageProps) {
  const { q } = await searchParams;
  const supabase = await createClient();
  
  const { data: { user } } = await supabase.auth.getUser();
  const permissions = user ? await getAdminPermissions(user.id) : null;

  let query = supabase
    .from('videos')
    .select('*')
    .order('created_at', { ascending: false });

  if (q) {
    query = query.or(`title.ilike.%${q}%,genre.ilike.%${q}%`);
  }

  const { data: videos, error } = await query;

  if (error) {
    console.error('Error fetching videos for admin:', error);
  }

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-2 h-8 bg-saffron rounded-full shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
            <h1 className="text-5xl font-bold font-heading text-white tracking-tight">
              Video <span className="text-white/40">Archive</span>
            </h1>
          </div>
          <p className="text-white/50 font-medium italic pl-5">Manage spiritual discourses and guided meditations.</p>
        </div>
        <div className="flex items-center gap-4">
          <Button variant="outline" size="sm" leftIcon={<Filter size={16} />} className="border-white/10 text-white/70 hover:text-white hover:bg-white/10 backdrop-blur-xl rounded-2xl transition-all duration-500 h-12 px-6">
            Refine View
          </Button>
          {permissions?.can_write && <AddVideoForm />}
        </div>
      </div>

      {/* Search Bar */}
      <SearchInput placeholder="Search the visual archive..." />

      <div className="glass-card overflow-hidden border border-white/5 shadow-2xl rounded-[2.5rem] bg-white/[0.02] backdrop-blur-3xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.03] border-b border-white/10 text-white/30 text-[10px] font-black uppercase tracking-[0.3em]">
                <th className="px-10 py-7">Video Details</th>
                <th className="px-10 py-7">Genre</th>
                <th className="px-10 py-7">Source</th>
                <th className="px-10 py-7 text-center">Status</th>
                <th className="px-10 py-7 text-right">Management</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {videos && videos.length > 0 ? (
                videos.map((video: VideoType) => (
                  <tr key={video.id} className="hover:bg-white/[0.04] transition-all duration-500 group">
                    <td className="px-10 py-8">
                      <div className="flex items-center gap-6">
                        <div className="relative w-32 h-18 bg-white/5 rounded-2xl overflow-hidden flex-shrink-0 group/thumb border border-white/10 shadow-2xl">
                          {video.thumbnail_url ? (
                            <img 
                              src={video.thumbnail_url} 
                              alt={video.title} 
                              className="w-full h-full object-cover transition-transform group-hover/thumb:scale-110 duration-700" 
                            />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center bg-saffron/5">
                              <PlayCircle size={24} className="text-saffron/40" />
                            </div>
                          )}
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/thumb:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-[2px]">
                            <Video size={24} className="text-white drop-shadow-[0_0_10px_rgba(255,0,0,0.5)]" />
                          </div>
                        </div>
                        <div className="flex flex-col gap-2 min-w-0">
                          <div className="font-bold text-white group-hover:text-saffron transition-colors text-xl tracking-tight italic line-clamp-1">
                            {video.title}
                          </div>
                          <a 
                            href={video.youtube_url} 
                            target="_blank" 
                            rel="noopener noreferrer" 
                            className="text-[10px] text-white/20 font-black tracking-widest uppercase flex items-center gap-2 hover:text-saffron transition-all"
                          >
                            <ExternalLink size={10} />
                            Watch on YouTube
                          </a>
                        </div>
                      </div>
                    </td>
                    <td className="px-10 py-8">
                      <span className="inline-flex items-center gap-2.5 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest bg-saffron/5 text-saffron border border-saffron/20 shadow-[0_0_20px_rgba(245,158,11,0.05)]">
                        <Tag size={12} />
                        {video.genre || 'General'}
                      </span>
                    </td>
                    <td className="px-10 py-8">
                      {video.is_own_content ? (
                        <span className="inline-flex items-center px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest bg-emerald-500/5 text-emerald-400 border border-emerald-500/20">
                          Original
                        </span>
                      ) : (
                        <span className="inline-flex items-center px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest bg-white/5 text-white/30 border border-white/10">
                          Curated
                        </span>
                      )}
                    </td>
                    <td className="px-10 py-8 text-center">
                      <span className={`inline-flex items-center gap-3 text-[10px] font-black uppercase tracking-[0.2em] ${
                        video.status === 'published' ? 'text-emerald-400' : 'text-saffron'
                      }`}>
                        <span className={`w-2 h-2 rounded-full ${
                          video.status === 'published' ? 'bg-emerald-400 shadow-[0_0_12px_rgba(52,211,153,0.6)] animate-pulse' : 'bg-saffron shadow-[0_0_12px_rgba(245,158,11,0.6)]'
                        }`} />
                        {video.status}
                      </span>
                    </td>
                    <td className="px-10 py-8 text-right">
                      <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all duration-500 translate-x-4 group-hover:translate-x-0">
                        {permissions?.can_edit && (
                          <Button variant="ghost" size="icon" className="h-11 w-11 text-white/20 hover:text-white hover:bg-white/10 rounded-2xl transition-all shadow-xl border border-transparent hover:border-white/5">
                            <Pencil size={20} />
                          </Button>
                        )}
                        {permissions?.can_delete && <DeleteVideoButton id={video.id} />}
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-10 py-40 text-center">
                    <div className="flex flex-col items-center max-w-sm mx-auto">
                      <div className="relative group/empty mb-10">
                        <div className="absolute inset-0 bg-saffron/20 blur-3xl rounded-full opacity-50 group-hover/empty:opacity-100 transition-opacity duration-1000" />
                        <div className="relative w-28 h-28 bg-white/[0.03] rounded-[2.5rem] flex items-center justify-center border border-white/10 backdrop-blur-3xl shadow-inner overflow-hidden">
                          <PlayCircle size={44} className="text-white/10 group-hover/empty:text-saffron transition-all duration-700 group-hover/empty:scale-110" />
                          <div className="absolute inset-0 bg-gradient-to-tr from-saffron/10 to-transparent opacity-0 group-hover/empty:opacity-100 transition-opacity" />
                        </div>
                      </div>
                      <h3 className="font-bold text-white text-3xl mb-4 tracking-tight">
                        {q ? 'No matching videos' : 'Archive is empty'}
                      </h3>
                      <p className="text-white/40 mb-12 text-base font-medium italic leading-relaxed font-serif">
                        {q 
                          ? `We couldn't find any videos matching "${q}". Please try an alternative path.` 
                          : 'Your collection of spiritual discourses is waiting to be built. Begin by anchoring your first video.'}
                      </p>
                      {permissions?.can_write && !q && (
                        <div className="flex justify-center scale-110">
                          <AddVideoForm />
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Footer Insight */}
      <div className="flex items-center justify-center py-6 text-[10px] font-black uppercase tracking-[0.4em] text-white/10">
        <Sparkles size={14} className="mr-4" />
        Illuminating the Path Through Sight
      </div>
    </div>
  );
}


